// C# — Bubble Sort
int[] arr = { 64, 34, 25, 12, 22, 11, 90 };
int n = arr.Length;

for (int i = 0; i < n - 1; i++)
{
    bool swapped = false;
    for (int j = 0; j < n - i - 1; j++)
    {
        if (arr[j] > arr[j + 1])
        {
            // swap
            int temp = arr[j];
            arr[j] = arr[j + 1];
            arr[j + 1] = temp;
            swapped = true;
        }
    }
    // early exit if no swaps occurred
    if (!swapped) break;
}
// arr = { 11, 12, 22, 25, 34, 64, 90 }

// C++ — Bubble Sort
#include <iostream>
using namespace std;

void bubbleSort(int arr[], int n) {
    for (int i = 0; i < n - 1; i++) {
        bool swapped = false;
        for (int j = 0; j < n - i - 1; j++) {
            if (arr[j] > arr[j + 1]) {
                swap(arr[j], arr[j + 1]);
                swapped = true;
            }
        }
        if (!swapped) break;
    }
}

int main() {
    int arr[] = {64, 34, 25, 12, 22, 11, 90};
    int n = sizeof(arr) / sizeof(arr[0]);
    bubbleSort(arr, n);
    // arr = {11, 12, 22, 25, 34, 64, 90}
    return 0;
}

// Java — Bubble Sort
public class BubbleSort {
    public static void bubbleSort(int[] arr) {
        int n = arr.length;
        for (int i = 0; i < n - 1; i++) {
            boolean swapped = false;
            for (int j = 0; j < n - i - 1; j++) {
                if (arr[j] > arr[j + 1]) {
                    int temp = arr[j];
                    arr[j] = arr[j + 1];
                    arr[j + 1] = temp;
                    swapped = true;
                }
            }
            if (!swapped) break;
        }
    }

    public static void main(String[] args) {
        int[] arr = {64, 34, 25, 12, 22, 11, 90};
        bubbleSort(arr);
        // arr = {11, 12, 22, 25, 34, 64, 90}
    }
}

// JavaScript — Bubble Sort
function bubbleSort(arr) {
    const n = arr.length;
    for (let i = 0; i < n - 1; i++) {
        let swapped = false;
        for (let j = 0; j < n - i - 1; j++) {
            if (arr[j] > arr[j + 1]) {
                [arr[j], arr[j + 1]] = [arr[j + 1], arr[j]]; // destructuring swap
                swapped = true;
            }
        }
        if (!swapped) break;
    }
    return arr;
}

const arr = [64, 34, 25, 12, 22, 11, 90];
bubbleSort(arr);
// arr = [11, 12, 22, 25, 34, 64, 90]
